// src/pages/vendor/VendorPortal.jsx
import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import { Badge, ComplaintCard } from '../../components/ComplaintCard';
import { KPI, NotifBanner, Modal, ModalHeader } from '../../components/UI';

export default function VendorPortal() {
  const { complaints, updateComplaint } = useApp();
  const [tab, setTab] = useState('tasks');
  const [selectedCleanerTask, setSelectedCleanerTask] = useState(null);
  const [notif, setNotif] = useState(null);

  // Cleaners dynamic allocation roster array list
  const cleanerStaff = [
    { id: 'c_01', name: 'Ramesh Kumar (Zone A)' },
    { id: 'c_02', name: 'Suresh Patil (Platform Squad)' },
    { id: 'c_03', name: 'Anil Deshmukh (Night Force)' }
  ];

  const handleAssign = async (complaintId, cleanerId) => {
    const cleaner = cleanerStaff.find(c => c.id === cleanerId);
    await updateComplaint(complaintId, {
      status: 'ASSIGNED_TO_CLEANER',
      assignedCleaner: cleaner
    });
    setSelectedCleanerTask(null);
    setNotif(`Task successfully handed over to ${cleaner.name}`);
  };

  const handleApproveClean = async (id) => {
    await updateComplaint(id, { status: 'COMPLETED', resolvedAt: new Date() });
    setNotif("Verification Approved! Database logged as absolute clean.");
  };

  return (
    <div style={{ display: 'flex', height: '100vh', fontFamily: 'system-ui,sans-serif', overflow: 'hidden' }}>
      <Sidebar title="Express Travel" subtitle="Vendor Engine" 
        navItems={[{ key: 'tasks', icon: '📋', label: 'Tasks Desk' }]} 
        activeTab={tab} onTabChange={setTab}
        footerUser={{ initials: 'RK', name: 'Rajesh Kumar', role: 'Vendor Head', avatarColor: '#1565C0' }} 
      />
      <div style={{ flex: 1, overflowY: 'auto', background: '#F7F9FC', padding: 22 }}>
        <div style={{ fontSize: 18, fontWeight: 800, marginBottom: 12 }}>Vendor Control Workspace</div>
        {notif && <NotifBanner msg={notif} type="green" onDone={() => setNotif(null)} />}

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(240px,1fr))', gap: 14 }}>
          {complaints.map(c => (
            <ComplaintCard key={c.id} complaint={c} actions={
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6, width: '100%' }}>
                
                {/* 1. Nayi ticket par Vendor Cleaner assign karega */}
                {c.status === 'NEW' && (
                  <button onClick={() => setSelectedCleanerTask(c)} style={{ background: '#4527A0', color: '#fff', border: 'none', padding: '6px 12px', borderRadius: 8, fontSize: 12, fontWeight: 700, cursor: 'pointer' }}>
                    📢 Assign Cleaner Force
                  </button>
                )}

                {/* Status displays for pipeline updates */}
                {c.status === 'ASSIGNED_TO_CLEANER' && (
                  <div style={{ fontSize: 12, color: '#1565C0', fontWeight: 600 }}>🏃 En Route: {c.assignedCleaner?.name}</div>
                )}

                {/* 2. Cleaner jab photo upload karega tab vendor verify button dekhega */}
                {c.status === 'CLEANED_BY_FORCE' && (
                  <div style={{ background: '#E8F5E9', padding: 8, borderRadius: 8, border: '1px solid #2E7D32' }}>
                    <div style={{ fontSize: 11, fontWeight: 700, color: '#2E7D32', marginBottom: 4 }}>✨ Cleaner Claimed Done!</div>
                    <img src={c.cleanerPhoto} alt="After cleanup" style={{ width: '100%', height: 80, objectFit: 'cover', borderRadius: 4, marginBottom: 6 }} />
                    <button onClick={() => handleApproveClean(c.id)} style={{ width: '100%', background: '#2E7D32', color: '#fff', border: 'none', padding: '5px', borderRadius: 6, fontSize: 11, fontWeight: 700, cursor: 'pointer' }}>
                      ✓ Approve Cleanup
                    </button>
                  </div>
                )}
              </div>
            } />
          ))}
        </div>
      </div>

      {/* Assignment Control Overlay Modal */}
      {selectedCleanerTask && (
        <Modal onClose={() => setSelectedCleanerTask(null)}>
          <ModalHeader title="Select Cleaner Personnel" sub={selectedCleanerTask.customTicketId} onClose={() => setSelectedCleanerTask(null)} />
          <div style={{ padding: '0 20px 20px' }}>
            <div style={{ fontSize: 13, marginBottom: 10, color: '#3D4F61' }}>Select crew member to deploy at <strong>{selectedCleanerTask.area}</strong>:</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
              {cleanerStaff.map(cleaner => (
                <button key={cleaner.id} onClick={() => handleAssign(selectedCleanerTask.id, cleaner.id)} style={{ padding: '12px', background: '#F7F9FC', border: '1px solid #DDE3E9', borderRadius: 8, textAlign: 'left', fontWeight: 600, cursor: 'pointer' }}
                  onMouseEnter={e => e.currentTarget.style.background = '#E3F2FD'}
                  onMouseLeave={e => e.currentTarget.style.background = '#F7F9FC'}>
                  🦺 {cleaner.name}
                </button>
              ))}
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}
